using Apex.Application.Abstractions.Data;
using Apex.Modules.Accounting.ChartOfAccounts.Domain;
using Apex.Modules.Accounting.ChartOfAccounts.Repositories.Rows;
using Dapper;

namespace Apex.Modules.Accounting.ChartOfAccounts.Repositories;

internal sealed class AccountClassReadRepository(IGeneralConnectionFactory factory):IAccountClassReadRepository
{
 public async Task<AccountClassRow?> GetAsync(long id,CancellationToken ct=default)=>await (await factory.OpenAsync(ct)).QuerySingleOrDefaultAsync<AccountClassRow>(new CommandDefinition("SELECT id Id,code Code,name Name,status Status,created_at CreatedAt,updated_at UpdatedAt,archived_at ArchivedAt FROM account_class WHERE id=@Id",new{Id=id},cancellationToken:ct));
 public async Task<IReadOnlyList<AccountClassRow>> ListAsync(bool includeArchived,CancellationToken ct=default)=>(await (await factory.OpenAsync(ct)).QueryAsync<AccountClassRow>(new CommandDefinition("SELECT id Id,code Code,name Name,status Status,created_at CreatedAt,updated_at UpdatedAt,archived_at ArchivedAt FROM account_class WHERE @IncludeArchived=1 OR status='ACTIVE' ORDER BY code,id",new{IncludeArchived=includeArchived},cancellationToken:ct))).AsList();
}
